import java.io.IOException;
import javax.servlet.ServletException;
import javax.servlet.annotation.WebServlet;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

@WebServlet("/xss-secure")
public class XssSecureServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        String userInput = request.getParameter("input");

        // Sanitize and escape user input before including it in the response
        String safeUserInput = escapeHtml(userInput);

        String output = "<html><body>User input: " + safeUserInput + "</body></html>";

        response.getWriter().write(output);
    }

    private String escapeHtml(String input) {
        if (input == null) {
            return "";
        }

        return input
            .replace("&", "&amp;")
            .replace("<", "&lt;")
            .replace(">", "&gt;")
            .replace("\"", "&quot;")

